            display: getOpen() ? "block" : "none",
            transform: `translate(${xVal}px, ${yVal}px)`,
          });
        });
    }

    // a bit nasty, we assign the cleanup to a nested property as state._cleanup
    // will trigger a reactive update, and leads to an immediate drop of listeners
    _refs.cleanup = floating.autoUpdate(
      triggerRef.current,
      floatingRef.current,
      update
    );
  }, [getOpen()]);
  useEffect(() => {
    if (typeof document === "undefined") return;

    // Always clean up previous listeners before re-evaluating attachment
    document.removeEventListener("click", _refs.onClickOutside);
    document.removeEventListener("keydown", _refs.onKeyDown);
    if (!getOpen()) return;
    function onClickOutside(event: any) {
      if (!getOpen()) return;

    if (!triggerRef.current || !floatingRef.current) return;

    // we need to target the content elements, not the ref wrappers
    const anchor = triggerRef.current.firstElementChild;
    const floating = floatingRef.current.firstElementChild;
    if (!anchor || !floating) return;

    // composedPath supports shadow-dom, anchor.contains(target) does not
    const path = event.composedPath();
    if (path.includes(anchor)) return;
    if (path.includes(floating)) return;
    setOpen(false, {
      reason: "outside",
      event,
    });
  }
  function onKeyDown(event: KeyboardEvent) {
    if (event.key === "Escape") {
      setOpen(false, {
        reason: "escape",
        event,
      });
    }
  }

  // reassign & store
  document.addEventListener("click", onClickOutside);
  document.addEventListener("keydown", onKeyDown);
  _refs.onClickOutside = onClickOutside;
  _refs.onKeyDown = onKeyDown;
}, [getOpen()]);
useEffect(() => {
  return () => {
    if (typeof document === "undefined") return;
    _refs.cleanup?.();
    document.removeEventListener("click", _refs.onClickOutside);
    document.removeEventListener("keydown", _refs.onKeyDown);
  };
}, []);

return (
  <>
    <div className="magicbell--floating-ui div-45c86259">
      <div ref={triggerRef}>
        <props.TriggerComponent
          open={getOpen()}
          onClick={(event) => toggle(event)}
        />
      </div>
      <div className="div-45c86259-2" ref={floatingRef}>

          {getOpen() ? (
            <props.FloatingComponent
              height={getHeight()}
              width={getWidth()}
              data={props.data}
              floating
              {...props.floatingComponentProps}
            />
          ) : null}
        </div>
      </div>
      <style>{`.div-45c86259 {
  position: relative;
}.div-45c86259-2 {
  position: absolute;
  left: 0px;
  top: 0px;
  will-change: transform;
}`}</style>
    </>
  );
}

